import java.io.BufferedInputStream
private class FastScanner { private val input=BufferedInputStream(System.`in`); private val buffer=ByteArray(1 shl 16); private var len=0; private var ptr=0; private fun readByte():Int{ if(ptr>=len){ len=input.read(buffer); ptr=0; if(len<=0)return -1}; return buffer[ptr++].toInt()}; fun nextInt():Int{ var c=readByte(); while(c<=32&&c>=0)c=readByte(); var v=0; while(c>32){ v=v*10+c-'0'.code; c=readByte()}; return v } }
fun isSelfCrossing(x:IntArray):Boolean{ for(i in 3 until x.size){ if(x[i]>=x[i-2] && x[i-1]<=x[i-3]) return true; if(i>=4 && x[i-1]==x[i-3] && x[i]+x[i-4]>=x[i-2]) return true; if(i>=5 && x[i-2]>=x[i-4] && x[i]+x[i-4]>=x[i-2] && x[i-1]<=x[i-3] && x[i-1]+x[i-5]>=x[i-3]) return true }; return false }
fun main(){ val fs=FastScanner(); val t=fs.nextInt(); val out=StringBuilder(); repeat(t){tc-> val n=fs.nextInt(); val x=IntArray(n){fs.nextInt()}; if(tc>0)out.append("\n\n"); out.append(if(isSelfCrossing(x)) "true" else "false") }; print(out.toString()) }
